// Helper to force delete a city in backend
const forceDeleteCity = async (userId: string, uniqueCityId: string) => {
  try {
    const api_key = localStorage.getItem('api_key');
    const payload = { user_id: userId, unique_city_id: uniqueCityId, ...(api_key ? { api_key } : {}) };
    console.log('Force deleting city with:', payload);
    const res = await fetchWithFallback(API_2_BASES, '/api/forcedelete/city', {
      method: 'DELETE',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    if (!res.ok) {
      const errorText = await res.text();
      throw new Error(`Force delete failed: ${errorText}`);
    }
    console.log('Force delete successful');
  } catch (err) {
    console.error('Force delete error:', err);
  }
};

