// API configuration
const API_BASE_URL_FILES = API_2_BASE;
const API_BASE_URL_CITY = API_2_BASE;

const API_ENDPOINTS = {
  city: '/api/city',
  routes: '/api/routes/upload',
  stops: '/api/stops/upload',
  trips: '/api/trips/upload',
  stopTimes: '/api/stop_times/upload',
  routeDetails: '/api/route_details/upload',
  vehicles: '/api/vehicles-data/upload',
  agency: '/api/agency/upload',
  depot: '/api/depot/upload',
  calendar: '/api/calendar/upload',
  calendarDates: '/api/calendar-dates/upload',
  transfers: '/api/transfers/upload'
};

// Utility function to format file size
const formatFileSize = (bytes: number): string => {
  if (bytes === 0) return '0 Bytes';
  const k = 1024;
  const sizes = ['Bytes', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
};

const uploadCityInfo = async (cityName: string, description: string): Promise<any> => {
  const userId = localStorage.getItem('userId');
  const api_key = localStorage.getItem('api_key');
  const response = await fetchWithFallback(API_2_BASES, API_ENDPOINTS.city, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      city_name: cityName,
      description: description,
      user_id: userId,
      ...(api_key ? { api_key } : {})
    })
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Failed to upload city info: ${errorText}`);
  }

  const result = await response.json();
  // Store unique_city_id in localStorage for file uploads
  const uniqueCityId = result?.data?.city?.unique_city_id;
  if (uniqueCityId) {
    localStorage.setItem('uniqueCityId', uniqueCityId);
  }
  return result;
};

const uploadFileToAPI = async (
  file: File,
  endpoint: string,
  cityName: string,
  onProgress: (progress: number, uploadedSize: string, speed: string) => void,
  baseIndex: number = 0
): Promise<any> => {
  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    const formData = new FormData();
    const startTime = Date.now();
    const api_key = localStorage.getItem('api_key');

    // Map the correct field name based on the endpoint
    const endpointToFieldMap: Record<string, string> = {
      '/api/routes/upload': 'routesFile',
      '/api/stops/upload': 'stopsFile',
      '/api/trips/upload': 'tripsFile',
      '/api/stop_times/upload': 'stopTimesFile',
      '/api/route_details/upload': 'routeDetailsFile',
      '/api/vehicles-data/upload': 'vehiclesFile',
      '/api/agency/upload': 'agencyFile',
      '/api/depot/upload': 'depotFile',
      '/api/calendar/upload': 'calendarFile',
      '/api/calendar-dates/upload': 'CalendarDatesFile',
      '/api/transfers/upload': 'transfersFile',
    };

    const fieldName = endpointToFieldMap[endpoint];

    if (!fieldName) {
      reject(new Error(`Unknown upload field for endpoint: ${endpoint}`));
      return;
    }

    formData.append(fieldName, file);
    // Some endpoints don't require city_name (and may reject unknown fields)
    if (!['/api/calendar-dates/upload', '/api/transfers/upload'].includes(endpoint)) {
      formData.append('city_name', cityName);
    }
    const userId = localStorage.getItem('userId');
    if (userId) {
      formData.append('user_id', userId);
    }
    const uniqueCityId = localStorage.getItem('uniqueCityId');
    if (uniqueCityId) {
      formData.append('unique_city_id', uniqueCityId);
    }
    if (api_key) {
      formData.append('api_key', api_key);
    }

    // Track upload progress
    xhr.upload.addEventListener('progress', (event) => {
      if (event.lengthComputable) {
        const percentage = (event.loaded / event.total) * 100;
        const uploadedSize = formatFileSize(event.loaded);
        const elapsedTime = (Date.now() - startTime) / 1000;
        const speed = elapsedTime > 0 ? formatFileSize(event.loaded / elapsedTime) + '/s' : '0 B/s';

        onProgress(percentage, uploadedSize, speed);
      }
    });

    // Handle successful response
    xhr.addEventListener('load', () => {
      if (xhr.status >= 200 && xhr.status < 300) {
        try {
          const response = JSON.parse(xhr.responseText);
          resolve(response);
        } catch {
          resolve({ success: true }); // fallback if response isn't JSON
        }
      } else {
        // Retry on server errors if a fallback base is available
        if (xhr.status >= 500 && baseIndex + 1 < API_2_BASES.length) {
          uploadFileToAPI(file, endpoint, cityName, onProgress, baseIndex + 1)
            .then(resolve)
            .catch(reject);
          return;
        }
        // Enhanced error handling for 400 with JSON body
        let errorMsg = `Failed to upload to ${endpoint}: ${xhr.statusText}`;
        try {
          const errorResponse = JSON.parse(xhr.responseText);
          if (errorResponse.message) {
            errorMsg = errorResponse.message;
            if (errorResponse.data && errorResponse.data.issues && Array.isArray(errorResponse.data.issues)) {
              errorMsg += '\nIssues:';
              errorMsg += '\n' + errorResponse.data.issues.join('\n');
            }
          }
        } catch (e) {
          // Not JSON, keep default errorMsg
        }
        reject(new Error(errorMsg));
      }
    });

    // Handle errors
    xhr.addEventListener('error', () => {
      if (baseIndex + 1 < API_2_BASES.length) {
        uploadFileToAPI(file, endpoint, cityName, onProgress, baseIndex + 1)
          .then(resolve)
          .catch(reject);
        return;
      }
      reject(new Error(`Network error during upload to ${endpoint}`));
    });

    xhr.addEventListener('timeout', () => {
      if (baseIndex + 1 < API_2_BASES.length) {
        uploadFileToAPI(file, endpoint, cityName, onProgress, baseIndex + 1)
          .then(resolve)
          .catch(reject);
        return;
      }
      reject(new Error(`Upload timeout for ${endpoint}`));
    });

    xhr.timeout = 300000; // 5 min timeout
    const base = API_2_BASES[baseIndex] || API_BASE_URL_FILES;
    xhr.open('POST', joinUrl(base, endpoint));
    xhr.send(formData);
  });
};

