  const firstName = localStorage.getItem('first_name') || '';
  const lastName = localStorage.getItem('last_name') || '';
  const displayName = (firstName || lastName) ? `${firstName} ${lastName}`.trim() : (userName.trim() || (username ? toTitle(username) : 'User'));
