  const [cityToDelete, setCityToDelete] = useState<City | null>(null);
  // Removed loadingCities state (was unused)

 useEffect(() => {
  const fetchCities = async () => {
    try {
      const userIdRaw = localStorage.getItem('userId');
      const userId = userIdRaw ? Number(userIdRaw) : undefined;
      const api_key = localStorage.getItem('api_key');
      const res = await fetchWithFallback(API_2_BASES, '/api/city/user', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user_id: userId, ...(api_key ? { api_key } : {}) })
      });
      const data = await res.json();
      // Expecting data.cities or data.data.cities
      const citiesFromApi = Array.isArray(data?.cities) ? data.cities : (Array.isArray(data?.data?.cities) ? data.data.cities : []);
      const apiCities = citiesFromApi.map((c: any) => ({
        id: (c.city_name || c.name || '').toLowerCase().replace(/\s+/g, '-'),
        name: c.city_name || c.name,
        description: c.description || (c.city_name ? `Explore ${c.city_name}'s transit system` : 'Explore this city\'s transit system'),
        imageUrl: 'data:image/png;base64,',
        enabled: true,
        isCustom: true,
        centerLat: c.center_lat,
        centerLon: c.center_lng,
        unique_city_id: c.unique_city_id || c.id // ensure unique_city_id is set from API
      }));

      // Backend now returns `image_url` per city; prefer it for tile images.
      // (If missing, we can still hydrate an uploaded image from localStorage below.)
      for (let i = 0; i < apiCities.length; i++) {
        const raw = citiesFromApi[i];
        const candidate = typeof raw?.image_url === 'string'
          ? raw.image_url.trim()
          : (typeof raw?.imageUrl === 'string' ? raw.imageUrl.trim() : '');
        const normalized = (!candidate || /^(data|blob):/i.test(candidate))
          ? ''
          : (/^https?:\/\//i.test(candidate)
            ? candidate
            : (candidate.startsWith('/') ? `${API_BASE_URL_CITY}${candidate}` : `${API_BASE_URL_CITY}/${candidate}`));
        apiCities[i].imageUrl = normalized;
      }

      // Merge user cities with default cities, avoiding duplicates
      // Hydrate API-provided custom cities with locally stored metadata (port only).
      // City tile images must use backend-provided `image_url`.
      let persistedCustomCities: any[] = [];
      try {
        const parsed = JSON.parse(localStorage.getItem('transit-cities') || '[]');
        persistedCustomCities = Array.isArray(parsed) ? parsed : [];
      } catch {
        persistedCustomCities = [];
      }

      const persistedById = new Map<string, any>();
      const persistedByUniqueId = new Map<string, any>();
      for (const city of persistedCustomCities) {
        if (city && typeof city.id === 'string') {
          persistedById.set(city.id, city);
        }
        const uniqueKey = city?.unique_city_id ?? city?.uniqueCityId ?? city?.unique_city_id;
        if (uniqueKey !== undefined && uniqueKey !== null) {
          persistedByUniqueId.set(String(uniqueKey), city);
        }
      }

      const apiCitiesHydrated = apiCities.map((city: any) => {
        const uniqueKey = city?.unique_city_id ?? city?.uniqueCityId ?? city?.unique_city_id;
        const persisted = persistedById.get(city.id) || (uniqueKey != null ? persistedByUniqueId.get(String(uniqueKey)) : undefined);
        const persistedPort = Number(persisted?.port);
        const port = Number.isFinite(persistedPort) ? persistedPort : city.port;

        // Only spread when we actually need to override something
        if (port === city.port) return city;
        return { ...city, port };
      });

      const seen = new Set();
      const merged = [...apiCitiesHydrated, ...defaultCities].filter(city => {
        if (seen.has(city.id)) return false;
        seen.add(city.id);
        return true;
      });
      setCities(merged);
    } catch (err) {
      console.error('Error fetching user cities:', err);
      setCities([]);
    } finally {
      // loading state removed
    }
  };
  fetchCities();
}, []);




